"""`tt` CLI — a self-contained interface to the Timelines.app store
and its cloud sync backend.
"""

from __future__ import annotations

import json
import re
import sys
from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
from types import SimpleNamespace
from typing import Callable

from rich import box
from rich.console import Console
from rich.table import Table
from rich.text import Text

from timetrack import Event, Timeline
from timetrack import api, changes
from timetrack.sync import (
    Countdown,
    CountdownOp,
    add_countdown_preset,
    add_event,
    delete_event,
    edit_event,
    fetch_cloud_state,
    list_countdowns,
    local_aware,
    remove_countdown_preset,
    start_countdown,
    start_timer,
    stop_countdown,
    stop_timer,
)

console = Console()
err_console = Console(stderr=True)


class CliError(Exception):
    """A user-facing argument-parsing error."""


@dataclass
class Flag:
    name: str            # long option, e.g. "--today"
    takes_value: bool
    help: str
    metavar: str = ""    # placeholder shown in help for value flags

    @property
    def attr(self) -> str:
        return self.name.lstrip("-").replace("-", "_")


@dataclass
class Arg:
    name: str            # positional name, e.g. "timeline"
    help: str
    required: bool = True
    variadic: bool = False   # captures all remaining positionals, space-joined


@dataclass
class Command:
    name: str
    help: str
    func: Callable[[SimpleNamespace], int]
    flags: list[Flag] = field(default_factory=list)
    args: list[Arg] = field(default_factory=list)


def color_hex(color: int | None) -> str | None:
    """Decode a Timelines RGB565-packed color int into a '#RRGGBB' string
    usable as a rich style. Returns None for a falsy/zero color."""
    if not color:
        return None
    r = (color >> 11) & 0x1F
    g = (color >> 5) & 0x3F
    b = color & 0x1F
    return f"#{round(r * 255 / 31):02X}{round(g * 255 / 63):02X}{round(b * 255 / 31):02X}"


def _effective_end(e: Event, now: datetime) -> datetime | None:
    """End used for duration/overlap: 'now' for a running timer, else the
    stored end (falling back to the start)."""
    if e.time_tracking_active:
        return now
    if e.end_date:
        return local_aware(e.end_date)
    return local_aware(e.start_date) if e.start_date else None


def overlapping_uids(events: list[Event], now: datetime) -> set[str]:
    """UIDs of events whose [start, effective-end) interval intersects another's.
    Sweep in start order, tracking the furthest end seen so far."""
    items = []
    for e in events:
        if not e.start_date:
            continue
        s = local_aware(e.start_date)
        end = _effective_end(e, now) or s
        items.append((s, max(end, s), e.unique_identifier))
    items.sort(key=lambda x: x[0])
    overlap: set[str] = set()
    max_end: datetime | None = None
    max_uid: str | None = None
    for s, end, uid in items:
        if max_end is not None and s < max_end:
            overlap.add(uid)
            if max_uid:
                overlap.add(max_uid)
        if max_end is None or end > max_end:
            max_end, max_uid = end, uid
    return overlap


def events_table(events: list[Event]) -> Table:
    """Render events as a table: color-swatched by timeline, running rows green
    (with a live duration), and time-overlapping rows red."""
    now = datetime.now(timezone.utc)
    overlap = overlapping_uids(events, now)
    table = Table(box=box.SIMPLE_HEAD, header_style="bold", expand=False)
    table.add_column("ID", style="dim", no_wrap=True)
    table.add_column("Start", no_wrap=True)
    table.add_column("Dur", justify="right", no_wrap=True)
    table.add_column("Timeline", no_wrap=True)
    table.add_column("Name")
    for e in events:
        start = e.start_date.astimezone().strftime("%Y-%m-%d %H:%M") if e.start_date else "?"
        eff_end = _effective_end(e, now)
        if e.start_date and eff_end is not None:
            dur = fmt_duration((eff_end - local_aware(e.start_date)).total_seconds())
            if e.time_tracking_active:
                dur += "…"  # ongoing
        else:
            dur = ""
        hexc = color_hex(e.marker_color)
        tl = Text()
        if hexc:
            tl.append("● ", style=hexc)
        tl.append(e.timeline_name or "?")
        name = Text(e.name) if e.name else Text("(unnamed)", style="dim")
        if e.unique_identifier in overlap:
            row_style = "red"          # overlap warning wins over the running highlight
        elif e.time_tracking_active:
            row_style = "bold green"
        else:
            row_style = None
        table.add_row(e.unique_identifier[:8], start, dur, tl, name, style=row_style)
    return table


def timelines_table(tls: list[Timeline]) -> Table:
    """Render timelines as a table with a color swatch and decoded hex."""
    table = Table(box=box.SIMPLE_HEAD, header_style="bold", expand=False)
    table.add_column("ID", style="dim", no_wrap=True)
    table.add_column("", no_wrap=True)  # color swatch
    table.add_column("Name")
    table.add_column("Color", style="dim", no_wrap=True)
    table.add_column("Flags", no_wrap=True)
    for t in tls:
        hexc = color_hex(t.color)
        swatch = Text("●", style=hexc) if hexc else Text(" ")
        flags = []
        if t.archived:
            flags.append("[yellow]archived[/yellow]")
        if not t.visible:
            flags.append("[dim]hidden[/dim]")
        table.add_row(
            t.unique_identifier[:8],
            swatch,
            Text(t.name, style=hexc or ""),
            hexc or str(t.color),
            Text.from_markup(" ".join(flags)) if flags else "",
        )
    return table


def _clock_time(s: str) -> tuple[int, int] | None:
    """Parse a bare clock time — 'HH:MM' or colon-less 'HMM'/'HHMM' (e.g. 930,
    2356) — into (hour, minute). None if it isn't a valid clock time."""
    m = re.fullmatch(r"(\d{1,2}):(\d{1,2})", s) or re.fullmatch(r"(\d{1,2})(\d{2})", s)
    if m is None:
        return None
    hh, mm = int(m[1]), int(m[2])
    return (hh, mm) if hh < 24 and mm < 60 else None


def _is_when_token(tok: str) -> bool:
    """True if a bare word is unmistakably a time: 'now', a clock time
    (13:00 / 1300 / 930), or a '+/-N[smhd]' offset. Deliberately narrower than
    parse_when (no ISO dates) so ordinary name words are never mistaken."""
    if tok == "now":
        return True
    if re.fullmatch(r"[+-]\d+[smhd]?", tok):
        return True
    return _clock_time(tok) is not None


def split_trailing_when(name: str | None, at: str | None) -> tuple[str | None, str | None]:
    """Let the time ride as the last positional: `tt start Transition 13:00`.
    If --at wasn't given and the final word of the (variadic) name arg looks
    like a time, peel it off and return it as the `at` string."""
    if at is not None or not name:
        return name, at
    words = name.split()
    if _is_when_token(words[-1]):
        return " ".join(words[:-1]) or None, words[-1]
    return name, at


def parse_when(s: str) -> datetime:
    """Accept ISO8601, or HH:MM / HHMM (today), or 'now' / '+N[mh]' / '-N[mh]'."""
    s = s.strip()
    now = datetime.now(tz=timezone.utc).astimezone()
    if s in ("now", ""):
        return now
    if s.startswith(("+", "-")):
        sign = 1 if s[0] == "+" else -1
        rest = s[1:]
        unit = "m"
        if rest and rest[-1] in "smhd":
            unit = rest[-1]
            rest = rest[:-1]
        n = int(rest)
        delta = {
            "s": timedelta(seconds=n),
            "m": timedelta(minutes=n),
            "h": timedelta(hours=n),
            "d": timedelta(days=n),
        }[unit]
        return now + sign * delta
    hm = _clock_time(s)
    if hm is not None:
        return now.replace(hour=hm[0], minute=hm[1], second=0, microsecond=0)
    try:
        dt = datetime.fromisoformat(s)
    except ValueError:
        raise SystemExit(f"error: could not parse time {s!r}")
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=now.tzinfo)
    return dt


def parse_duration(s: str) -> timedelta:
    """Parse a duration like '1h30m', '90m', '2h', '45' (bare number = minutes)."""
    s = s.strip().lower()
    if not s:
        raise SystemExit("error: empty duration")
    if s.isdigit():
        return timedelta(minutes=int(s))
    units = {"s": 1, "m": 60, "h": 3600, "d": 86400}
    total = 0
    num = ""
    matched = False
    for ch in s:
        if ch.isdigit():
            num += ch
        elif ch in units and num:
            total += int(num) * units[ch]
            num = ""
            matched = True
        else:
            raise SystemExit(f"error: could not parse duration {s!r}")
    if num or not matched:
        raise SystemExit(f"error: could not parse duration {s!r}")
    return timedelta(seconds=total)


def fmt_duration(seconds: float) -> str:
    s = int(seconds)
    if s < 60:
        return f"{s}s"
    m, s = divmod(s, 60)
    if m < 60:
        return f"{m}m{s:02d}s" if s else f"{m}m"
    h, m = divmod(m, 60)
    return f"{h}h{m:02d}m"


def cloud_state() -> tuple[dict[str, Event], dict[str, Timeline], int]:
    """Pull current cloud events + timelines (the single source of truth), or
    exit with a clear error. Needs only the auth env vars — no local app."""
    try:
        events, timelines, _cobjs, _client, counter = fetch_cloud_state()
    except Exception as e:
        err_console.print(f"[bold red]error:[/bold red] cloud fetch failed: {e}")
        raise SystemExit(1)
    return events, timelines, counter


# ---------- commands ----------


def cmd_status(args: SimpleNamespace) -> int:
    events, timelines, counter = cloud_state()
    tls = list(timelines.values())
    active = sum(1 for t in tls if not t.archived)
    console.print(f"[bold]source:[/bold]    [dim]cloud.timelines.app (counter {counter})[/dim]")
    console.print(f"[bold]timelines:[/bold] {active} active [dim]({len(tls)} total)[/dim]")
    console.print(f"[bold]events:[/bold]    {len(events)}")
    running = next((e for e in events.values() if e.time_tracking_active), None)
    if running is not None:
        started = running.start_date.astimezone().strftime("%H:%M") if running.start_date else "?"
        elapsed = (
            fmt_duration((datetime.now(timezone.utc) - local_aware(running.start_date)).total_seconds())
            if running.start_date
            else "?"
        )
        line = Text("running:   ", style="bold")
        line.append("⏵ ", style="bold green")
        line.append(running.timeline_name or "?", style=color_hex(running.marker_color) or "")
        line.append(f"  {running.name or '(unnamed)'}")
        line.append(f"  {elapsed}", style="bold green")
        line.append(f"  since {started}", style="dim")
        console.print(line)
    else:
        console.print("[bold]running:[/bold]   [dim]none[/dim]")
    return 0


def cmd_events(args: SimpleNamespace) -> int:
    events_by_uid, _timelines, _counter = cloud_state()
    events = list(events_by_uid.values())
    if args.today:
        today = datetime.now().strftime("%Y-%m-%d")
        events = [e for e in events if e.day_identifier == today]
    if args.since:
        cutoff = parse_when(args.since).astimezone(timezone.utc)
        events = [e for e in events if e.start_date and e.start_date >= cutoff]
    if args.past:
        now = datetime.now(timezone.utc)
        events = [e for e in events if e.start_date and local_aware(e.start_date) <= now]
    if args.timeline:
        events = [
            e
            for e in events
            if (e.timeline_identifier and e.timeline_identifier.startswith(args.timeline.upper()))
            or e.timeline_name == args.timeline
        ]
    events.sort(key=lambda e: e.start_date or datetime.min.replace(tzinfo=timezone.utc))
    if args.json:
        print(json.dumps([e.to_json_dict() for e in events], indent=2, default=str))
        return 0
    if not events:
        console.print("[dim]no events[/dim]")
        return 0
    console.print(events_table(events))
    return 0


def cmd_timelines(args: SimpleNamespace) -> int:
    _events, timelines, _counter = cloud_state()
    tls = [t for t in timelines.values() if not t.archived or args.all]
    tls.sort(key=lambda t: t.order)
    if args.json:
        print(json.dumps([t.to_json_dict() for t in tls], indent=2, default=str))
        return 0
    if not tls:
        console.print("[dim]no timelines[/dim]")
        return 0
    console.print(timelines_table(tls))
    return 0


def _fmt_change_ts(ts: str | None) -> str:
    """Render a change's ISO timestamp as local 'MM-DD HH:MM', best-effort."""
    if not ts:
        return "?"
    s = ts[:-1] + "+00:00" if ts.endswith("Z") else ts
    try:
        return datetime.fromisoformat(s).astimezone().strftime("%m-%d %H:%M")
    except ValueError:
        return ts


def changes_table(records: list[dict]) -> Table:
    """Render change records: when, what action, which event, which fields."""
    table = Table(box=box.SIMPLE_HEAD, header_style="bold", expand=False)
    table.add_column("When", no_wrap=True)
    table.add_column("Action", no_wrap=True)
    table.add_column("ID", style="dim", no_wrap=True)
    table.add_column("Fields")
    styles = {"create": "green", "edit": "yellow", "delete": "red"}
    for rec in records:
        action = rec.get("action", "?")
        fields = rec.get("changedFields") or {}
        summary = ", ".join(fields) if fields else ("—" if action == "delete" else "")
        table.add_row(
            _fmt_change_ts(rec.get("timestamp")),
            Text(action, style=styles.get(action, "")),
            (rec.get("uniqueIdentifier") or "?")[:8],
            summary,
        )
    return table


def cmd_changes(args: SimpleNamespace) -> int:
    """Emit atomic event changes since a counter. Stateless: the caller stores
    the returned counter and decides what to do with the changes.

    With no --since, reports just the cloud's current counter (a seed point).
    With --since N, returns every event change newer than N.
    """
    try:
        if args.since is None:
            counter, recs = changes.current_counter(), []
        else:
            counter, recs = changes.changes_since(int(args.since))
    except ValueError:
        err_console.print(f"[bold red]error:[/bold red] --since must be an integer")
        return 2
    except Exception as e:
        err_console.print(f"[bold red]error:[/bold red] cloud fetch failed: {e}")
        return 1

    if args.json:
        print(json.dumps({"counter": counter, "changes": recs}, ensure_ascii=False))
        return 0
    if args.since is None:
        console.print(f"counter: [bold]{counter}[/bold]")
        return 0
    if not recs:
        console.print(f"[dim]no changes since {args.since} (counter {counter})[/dim]")
        return 0
    console.print(changes_table(recs))
    console.print(f"[dim]{len(recs)} change(s); counter now {counter}[/dim]")
    return 0


def cmd_auth(args: SimpleNamespace) -> int:
    """Save a sync session to ~/.config/timelines/auth.json.

    Since there's no real signin flow, this bootstraps the session from the
    TIMELINES_AUTH_TOKEN/TIMELINES_DEVICE_UUID env vars (loaded by direnv from
    .envrc), falling back to scraping the Timelines app's Cache.db."""
    try:
        if args.from_cache:
            auth = api.load_auth_from_cache()
            source = "app cache (Cache.db)"
        else:
            auth = api.load_auth_from_env()
            if auth is not None:
                source = f"env ({api.ENV_TOKEN}/{api.ENV_DEVICE_UUID})"
            else:
                auth = api.load_auth_from_cache()
                source = "app cache (Cache.db)"
    except Exception as e:
        err_console.print(f"[bold red]error:[/bold red] {e}")
        return 1
    path = api.save_auth(auth)
    console.print(f"[bold green]✓ saved session[/bold green] [dim]from {source}[/dim]")
    console.print(f"  [dim]→ {path}[/dim]")
    console.print(
        f"  [dim]device[/dim] {auth.device_uuid[:8]}…  [dim]token[/dim] …{auth.token[-6:]}"
    )
    return 0


def cmd_doctor(args: SimpleNamespace) -> int:
    """Verify what the CLI needs: a usable auth session + cloud reachability."""
    ok = True

    def check(label: str, passed: bool, detail: str = "") -> None:
        nonlocal ok
        mark = "[green]✓[/green]" if passed else "[red]✗[/red]"
        console.print(f"  {mark} {label}")
        if detail:
            console.print(f"      [dim]{detail}[/dim]")
        if not passed:
            ok = False

    console.print("[bold]timelines doctor[/bold]")
    console.print()
    console.print("[bold underline]Auth[/bold underline]")
    env_auth = api.load_auth_from_env()
    file_auth = api.load_auth_from_file()
    auth = env_auth or file_auth
    if env_auth is not None:
        src = f"env ({api.ENV_TOKEN} + {api.ENV_DEVICE_UUID})"
    elif file_auth is not None:
        src = f"session file ({api.SESSION_PATH})"
    else:
        src = ""
    check(
        "auth available",
        auth is not None,
        f"from {src}, device={auth.device_uuid[:8]}…"
        if auth is not None
        else f"set the env vars via direnv, or run `{PROG} auth`",
    )

    console.print()
    console.print("[bold underline]Cloud[/bold underline]")
    if auth is None:
        console.print(f"  [yellow]⊘[/yellow] [dim]skipped — set up auth first (`{PROG} auth`)[/dim]")
        ok = False
    else:
        try:
            counter = api.SyncClient().discover_counter()
            check("cloud.timelines.app reachable", True, f"globalCounter={counter}")
        except Exception as e:
            check("cloud.timelines.app reachable", False, str(e))

    console.print()
    if ok:
        console.print("status: [bold green]OK[/bold green]")
    else:
        console.print(
            "status: [bold red]FAIL[/bold red] [dim]— fix the items above[/dim]"
        )
    return 0 if ok else 1


# ---------- write commands (start / stop / edit / delete) ----------


def _op_line(head_markup: str, e: Event, tail: str = "") -> Text:
    """A status line: controlled markup head + a color swatch + plain (escaped-
    by-construction) event fields appended as Text."""
    line = Text.from_markup(head_markup + " ")
    hexc = color_hex(e.marker_color)
    if hexc:
        line.append("● ", style=hexc)
    line.append(e.timeline_name or "?")
    if e.name:
        line.append(f"  {e.name}")
    if tail:
        line.append(f"  {tail}", style="dim")
    return line


def _span(e: Event) -> str:
    if not e.start_date:
        return ""
    s = e.start_date.astimezone().strftime("%Y-%m-%d %H:%M")
    if e.end_date:
        return s + "–" + e.end_date.astimezone().strftime("%H:%M")
    return s


def cmd_add(args: SimpleNamespace) -> int:
    if not args.start:
        err_console.print("[bold red]error:[/bold red] add requires --start")
        return 2
    duration = getattr(args, "for")
    if args.end and duration:
        err_console.print("[bold red]error:[/bold red] pass either --end or --for, not both")
        return 2
    start = parse_when(args.start)
    if args.end:
        end = parse_when(args.end)
    elif duration:
        end = start + parse_duration(duration)
    else:
        err_console.print("[bold red]error:[/bold red] add requires --end or --for")
        return 2
    r = add_event(
        args.timeline,
        name=args.name or "",
        notes=args.notes or "",
        start=start,
        end=end,
        dry_run=args.dry_run,
    )
    if r.error:
        err_console.print(f"[bold red]error:[/bold red] {r.error}")
        return 1
    e = r.event
    dur = fmt_duration((local_aware(e.end_date) - local_aware(e.start_date)).total_seconds())
    head = "[dim]would add[/dim]" if r.dry_run else "[bold green]＋ added[/bold green]"
    console.print(_op_line(head, e, f"{_span(e)} ({dur})"))
    return 0


def cmd_start(args: SimpleNamespace) -> int:
    name, at_str = split_trailing_when(args.name, args.at)
    at = parse_when(at_str) if at_str else None
    r = start_timer(
        args.timeline,
        name=name or "",
        notes=args.notes or "",
        at=at,
        stop_running=not args.no_stop,
        dry_run=args.dry_run,
    )
    if r.error:
        err_console.print(f"[bold red]error:[/bold red] {r.error}")
        return 1
    if r.stopped is not None:
        console.print(_op_line("[dim]⏹ stopped[/dim]", r.stopped))
    head = "[dim]would start[/dim]" if r.dry_run else "[bold green]⏵ started[/bold green]"
    started = r.event.start_date.astimezone().strftime("%H:%M")
    console.print(_op_line(head, r.event, f"at {started}"))
    return 0


def cmd_stop(args: SimpleNamespace) -> int:
    at_str = args.at or args.when
    at = parse_when(at_str) if at_str else None
    r = stop_timer(at=at, dry_run=args.dry_run)
    if r.error:
        err_console.print(f"[bold red]error:[/bold red] {r.error}")
        return 1
    e = r.event
    dur = (
        fmt_duration((local_aware(e.end_date) - local_aware(e.start_date)).total_seconds())
        if e.start_date and e.end_date
        else "?"
    )
    head = "[dim]would stop[/dim]" if r.dry_run else "[bold]⏹ stopped[/bold]"
    console.print(_op_line(head, e, f"({dur})"))
    return 0


def cmd_edit(args: SimpleNamespace) -> int:
    r = edit_event(
        args.id,
        name=args.name,
        timeline=args.timeline,
        notes=args.notes,
        start=parse_when(args.start) if args.start else None,
        end=parse_when(args.end) if args.end else None,
        dry_run=args.dry_run,
    )
    if r.error:
        err_console.print(f"[bold red]error:[/bold red] {r.error}")
        return 1
    head = "[dim]would edit[/dim]" if r.dry_run else "[bold]✎ edited[/bold]"
    console.print(_op_line(head, r.event, _span(r.event)))
    return 0


def cmd_delete(args: SimpleNamespace) -> int:
    preview = args.dry_run or not args.yes
    r = delete_event(args.id, dry_run=preview)
    if r.error:
        err_console.print(f"[bold red]error:[/bold red] {r.error}")
        return 1
    head = "[dim]would delete[/dim]" if preview else "[bold red]🗑 deleted[/bold red]"
    console.print(_op_line(head, r.event, _span(r.event)))
    if preview and not args.dry_run:
        console.print("[dim]pass --yes to actually delete[/dim]")
    return 0


# ---------- countdown timers ----------


def _fmt_secs(seconds: float) -> str:
    """Compact m:ss / h:mm:ss for a countdown's remaining/duration."""
    s = max(0, int(round(seconds)))
    h, rem = divmod(s, 3600)
    m, s = divmod(rem, 60)
    return f"{h}:{m:02d}:{s:02d}" if h else f"{m}:{s:02d}"


def _cd_swatch(cd: Countdown) -> Text:
    line = Text()
    hexc = color_hex(cd.timeline_color)
    if hexc:
        line.append("● ", style=hexc)
    line.append(cd.timeline_name or "?")
    if cd.name:
        line.append(f"  {cd.name}")
    return line


def _cd_line(head_markup: str, cd: Countdown, tail: str = "") -> Text:
    line = Text.from_markup(head_markup + " ")
