    table.add_column("Timer")
    table.add_column("Duration", no_wrap=True)
    table.add_column("Status", no_wrap=True)
    for cd in cds:
        if cd.running and cd.remaining_seconds is not None:
            status = Text(f"⏳ {_fmt_secs(cd.remaining_seconds)} left", style="green")
        else:
            status = Text("idle", style="dim")
        table.add_row(_cd_swatch(cd), _fmt_secs(cd.duration_seconds), status)
    return table


