func (s *Store) TaskByID(id string) (*Task, error) {
	if strings.TrimSpace(id) == "" {
		return nil, sql.ErrNoRows
	}
	filter := TaskFilter{
		IncludeTrashed:        true,
		ExcludeTrashedContext: false,
		IncludeChecklist:      true,
	}
