		args = append(args, *filter.Status)
	}
	b.WriteString(" AND t.rt1_recurrenceRule IS NULL")
	b.WriteString(" ORDER BY t.\"index\"")

	rows, err := s.conn.Query(b.String(), args...)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	projects := make([]Project, 0, 32)
	for rows.Next() {
		var p Project
		var areaID sql.NullString
