"""The few operations the URL scheme cannot do, via AppleScript.

Only deletion (→ Trash) and emptying the Trash live here. Requires Things
to be running and macOS automation permission for the invoking terminal
(a one-time system prompt).
"""

from __future__ import annotations

import subprocess


class ScriptError(Exception):
    """A user-facing osascript failure."""


_AS_CLASS = {"todo": "to do", "project": "project", "area": "area", "tag": "tag"}


def _escape(s: str) -> str:
    return s.replace("\\", "\\\\").replace('"', '\\"')


def _run(script: str) -> str:
    proc = subprocess.run(
        ["osascript", "-"], input=script, capture_output=True, text=True
    )
    if proc.returncode != 0:
        detail = proc.stderr.strip() or f"osascript exited {proc.returncode}"
        raise ScriptError(detail)
    return proc.stdout.strip()


def delete(kind: str, id: str) -> None:
    """Delete by UUID. Todos and projects move to the Trash (recoverable);
    areas and tags are removed outright."""
    cls = _AS_CLASS.get(kind)
    if cls is None:
        raise ScriptError(f"cannot delete a {kind} via AppleScript")
    _run(
        'tell application "Things3"\n'
        f'  delete (first {cls} whose id is "{_escape(id)}")\n'
        "end tell"
    )


def empty_trash() -> None:
    _run('tell application "Things3"\n  empty trash\nend tell')

