"""Direct HTTP client for the Glimsoft Timelines cloud sync backend.

Replaces the need to open the Timelines app after every CLI write. We talk
straight to `https://cloud.timelines.app/sync` using the sync-hash formula
reverse-engineered on 2026-04-14 via mitmproxy capture:

    empty pull:  sha256(str(counter) + SALT)
    write:       sha256(str(first_changeset_id) + str(counter) + SALT)

where SALT = "mY-CuSTom_s_A_l_T". The write hash binds the client-generated
changeset UUID to the counter; the body bytes are not hashed.

Auth is scraped from the Timelines app's own NSURLCache (`Cache.db`), where
the most recent /sync request is archived with its Bearer token and the
device identifier. No signup / signin needed.
"""

from __future__ import annotations

import gzip
import hashlib
import json
import os
import plistlib
import sqlite3
import uuid
from dataclasses import dataclass
from datetime import datetime, timezone
from pathlib import Path
from typing import Any
from urllib.error import HTTPError, URLError
from urllib.request import Request, urlopen


SALT = "mY-CuSTom_s_A_l_T"
SYNC_URL = "https://cloud.timelines.app/sync"
DISCOVER_COUNTER = 999999  # any large value — server returns actual counter

# The iOS-on-Mac container UUID differs per install, so glob for it.
CACHE_DB_GLOB = "Library/Containers/*/Data/Library/Caches/com.glimsoft.Timelines/Cache.db"


def find_cache_db() -> Path:
    matches = sorted(Path.home().glob(CACHE_DB_GLOB))
    if not matches:
        raise FileNotFoundError(
            f"No Timelines Cache.db found under ~/{CACHE_DB_GLOB}. "
            "Install the Timelines iOS app from the Mac App Store and open it "
            "once so it hits /sync."
        )
    return max(matches, key=lambda p: p.stat().st_mtime)

STORE_PATH = Path.home() / "Library/Group Containers/group.glimsoft.Timelines/TimelinesModel"

CORE_DATA_EPOCH = 978307200.0  # seconds between 1970 and 2001


@dataclass
class SyncAuth:
    token: str       # bearer token, without the "Bearer " prefix
    device_uuid: str # the deviceIdentifier string


# ---------- Auth discovery ----------

ENV_TOKEN = "TIMELINES_AUTH_TOKEN"
ENV_DEVICE_UUID = "TIMELINES_DEVICE_UUID"

# Saved-session file. Mirrors how `ntn`/`td` persist a session under
# ~/.config/<tool>/ so you don't re-export env vars every shell. Since there's
# no real signin flow, `tt auth` bootstraps this file from the env vars (loaded
# by direnv from .envrc) or, as a fallback, from the app's Cache.db.
CONFIG_DIR = Path.home() / ".config" / "timelines"
SESSION_PATH = CONFIG_DIR / "auth.json"


def load_auth_from_env() -> SyncAuth | None:
    """Build auth from the TIMELINES_AUTH_TOKEN / TIMELINES_DEVICE_UUID env
    vars (e.g. exported by direnv or your shell profile). Returns None if
    either is unset."""
    token = os.environ.get(ENV_TOKEN)
    device_uuid = os.environ.get(ENV_DEVICE_UUID)
    if not token or not device_uuid:
        return None
    return SyncAuth(
        token=token.removeprefix("Bearer ").strip(),
        device_uuid=device_uuid.strip(),
    )


def load_auth_from_file(path: Path = SESSION_PATH) -> SyncAuth | None:
    """Read a saved session from the on-disk session file. Returns None if the
    file is missing, unreadable, or incomplete."""
    try:
        data = json.loads(path.read_text())
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return None
    token = data.get("token")
    device_uuid = data.get("device_uuid")
    if not token or not device_uuid:
        return None
    return SyncAuth(
        token=str(token).removeprefix("Bearer ").strip(),
        device_uuid=str(device_uuid).strip(),
    )


def save_auth(auth: SyncAuth, path: Path = SESSION_PATH) -> Path:
    """Persist a session to the on-disk session file (mode 0600). Returns the
    path written."""
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(
        json.dumps(
            {"version": 1, "token": auth.token, "device_uuid": auth.device_uuid},
            indent=2,
        )
        + "\n"
    )
    path.chmod(0o600)
    return path


def load_auth() -> SyncAuth:
    """Resolve sync auth, erroring clearly if unavailable.

    Resolution order: the TIMELINES_AUTH_TOKEN + TIMELINES_DEVICE_UUID env vars
    (override, e.g. for CI/direnv), then the saved session file. Run `tt auth`
    to populate the session file."""
    auth = load_auth_from_env() or load_auth_from_file()
    if auth is None:
        raise RuntimeError(
            f"No Timelines auth. Set {ENV_TOKEN} + {ENV_DEVICE_UUID} (e.g. via "
            f"direnv), or run `tt auth` to save a session to {SESSION_PATH}."
        )
    return auth


def load_auth_from_cache(cache_db: Path | None = None) -> SyncAuth:
    """Pull token + device UUID out of the Timelines app's CFURLCache."""
    if cache_db is None:
        cache_db = find_cache_db()
    if not cache_db.exists():
        raise FileNotFoundError(
            f"Timelines Cache.db not found at {cache_db}. Has the app ever "
            "opened and synced at least once?"
        )
    conn = sqlite3.connect(str(cache_db))
    try:
        row = conn.execute(
            "SELECT b.request_object FROM cfurl_cache_blob_data b "
            "JOIN cfurl_cache_response r ON r.entry_ID = b.entry_ID "
            "WHERE r.request_key = ?",
            (SYNC_URL,),
        ).fetchone()
    finally:
        conn.close()
    if row is None:
        raise RuntimeError(
            "No cached /sync request in Cache.db. Open the Timelines app "
            "once to let it hit /sync, then retry."
        )
    archive = plistlib.loads(row[0])

    token: str | None = None
    device_uuid: str | None = None
    for obj in archive.get("Array", []):
        if isinstance(obj, dict) and "Authorization" in obj:
            token = obj["Authorization"].removeprefix("Bearer ").strip()
        elif isinstance(obj, list) and obj and isinstance(obj[0], (bytes, bytearray)):
            try:
                raw = b"".join(obj)
                if raw[:2] == b"\x1f\x8b":
                    raw = gzip.decompress(raw)
                body = json.loads(raw.decode())
                device_uuid = body.get("deviceIdentifier")
            except Exception:
                continue
    if not token or not device_uuid:
        raise RuntimeError(
            "Could not extract token/device UUID from cached /sync request."
        )
    return SyncAuth(token=token, device_uuid=device_uuid)


# ---------- Hash formulas ----------


def hash_empty(counter: int) -> str:
    return hashlib.sha256(f"{counter}{SALT}".encode()).hexdigest()


def hash_write(changeset_id: str, counter: int) -> str:
    return hashlib.sha256(f"{changeset_id}{counter}{SALT}".encode()).hexdigest()


# ---------- Client ----------


class SyncClient:
    def __init__(self, auth: SyncAuth | None = None):
        self.auth = auth or load_auth()

    def _post(self, body: dict, hash_: str) -> dict:
        data = json.dumps(body).encode()
        req = Request(
            SYNC_URL,
            data=data,
            method="POST",
            headers={
                "Content-Type": "application/json",
                "Authorization": f"Bearer {self.auth.token}",
                "X-Timelines-sync-hash": hash_,
            },
        )
        try:
            with urlopen(req, timeout=30) as resp:
                return json.loads(resp.read().decode())
        except HTTPError as e:
            raise RuntimeError(
                f"/sync returned HTTP {e.code}: {e.read().decode(errors='replace')[:200]}"
            ) from e
        except URLError as e:
            raise RuntimeError(f"/sync network error: {e.reason}") from e

    def discover_counter(self) -> int:
        """Empty-pull a far-future counter so the server replies with its own."""
        resp = self._post(
            {
                "deviceIdentifier": self.auth.device_uuid,
                "latestKnownGlobalCounter": DISCOVER_COUNTER,
                "changesets": [],
            },
            hash_empty(DISCOVER_COUNTER),
        )
        return int(resp["newGlobalCounter"])

    def push_changeset(self, changeset: dict, counter: int) -> dict:
        """Send one changeset directly. Returns the server response dict."""
        body = {
            "deviceIdentifier": self.auth.device_uuid,
            "latestKnownGlobalCounter": counter,
            "changesets": [changeset],
        }
        return self._post(body, hash_write(changeset["id"], counter))

    def pull_changesets_since(
        self, counter: int = 0, *, max_rounds: int = 200
    ) -> list[dict]:
        """Download every changeset with globalCounter > `counter`.

        Paginated: each empty-pull returns at most `newChangesetsChangesCount`
        changes. We advance the counter based on the last changeset we saw and
        re-pull until `hasMoreChanges` is false. The server sometimes returns
        `newChangesets=[]` with `hasMoreChanges=true` during gaps; we still
        advance using `newGlobalCounter` so we never loop forever.
        """
        out: list[dict] = []
        seen_ids: set[str] = set()
        for _ in range(max_rounds):
            resp = self._post(
                {
                    "deviceIdentifier": self.auth.device_uuid,
                    "latestKnownGlobalCounter": counter,
                    "changesets": [],
                },
                hash_empty(counter),
            )
            ncs = resp.get("newChangesets") or []
            for cs in ncs:
                cs_id = cs.get("id")
                if cs_id and cs_id in seen_ids:
                    continue
                if cs_id:
                    seen_ids.add(cs_id)
                out.append(cs)
                gc = cs.get("globalCounter")
                if isinstance(gc, int) and gc > counter:
                    counter = gc
            server_counter = int(resp.get("newGlobalCounter") or counter)
            if server_counter > counter:
                counter = server_counter
            if not resp.get("hasMoreChanges"):
                return out
        raise RuntimeError(
            f"cloud pull exceeded {max_rounds} rounds — server kept reporting "
            "hasMoreChanges=true (possible pagination bug)"
        )


# ---------- Flushing pending ZCHANGESETs ----------


_ISO = "%Y-%m-%dT%H:%M:%S.%f"


def _ms_to_iso(ms: float) -> str:
    """Convert unix-ms (Swift JSONEncoder.millisecondsSince1970) to ISO."""
    dt = datetime.fromtimestamp(ms / 1000, tz=timezone.utc)
    return dt.strftime(_ISO)[:-3] + "Z"  # trim to millisecond precision


def _convert_date_fields(obj: Any) -> Any:
    """Recursively convert numeric date fields in change dicts to ISO strings.

    Swift's server expects ISO8601 strings for date fields; our ZCHANGESET
    blobs store them as floats (millisecondsSince1970). We fix them on the
    way out so the wire format matches what the app would send.
    """
    DATE_KEYS = {
        "startDate", "endDate", "lastModifiedDate", "dayIdentifier",
        "creationDate", "creationTime", "timestamp",
    }
    if isinstance(obj, dict):
        out = {}
        for k, v in obj.items():
            if k in DATE_KEYS and isinstance(v, (int, float)) and k != "dayIdentifier":
                out[k] = _ms_to_iso(float(v))
            else:
                out[k] = _convert_date_fields(v)
        return out
    if isinstance(obj, list):
        return [_convert_date_fields(v) for v in obj]
    return obj


def _deserialize_zchangeset_blob(blob: bytes) -> list[dict]:
    """ZCHANGESET blob columns are UTF-8 JSON arrays."""
    if not blob or blob == b"[]":
        return []
    return json.loads(blob.decode("utf-8"))


@dataclass
class FlushResult:
    pushed: int
    failed: int
    remaining: int
    errors: list[str]


def flush_pending_changesets(
    store_path: Path = STORE_PATH,
    client: SyncClient | None = None,
) -> FlushResult:
    """Walk ZCHANGESET where ZSTATE=2, POST each to /sync, delete on success.

    Uses the cracked write-hash formula. Runs serially (one changeset per
    request) so the counter can advance between writes based on the server's
    response.
    """
    client = client or SyncClient()
    current_counter = client.discover_counter()

    conn = sqlite3.connect(str(store_path))
    try:
        rows = conn.execute(
            "SELECT Z_PK, ZID, ZGLOBALCOUNTER, ZTIMESTAMP, "
            "ZEVENTCHANGES, ZTIMELINECHANGES, ZCOLORCHANGES, "
            "ZPREFERENCECHANGES, ZGOALCHANGES, ZCUSTOMOBJECTCHANGES "
            "FROM ZCHANGESET WHERE ZSTATE = 2 ORDER BY Z_PK"
        ).fetchall()

        pushed = 0
        errors: list[str] = []
        for (
            z_pk, z_id_bytes, zg_counter, ztimestamp,
            evc, tlc, cc, pc, gc, coc,
        ) in rows:
            cs_id = str(uuid.UUID(bytes=bytes(z_id_bytes))).upper()
            ts_dt = datetime.fromtimestamp(
                float(ztimestamp) + CORE_DATA_EPOCH, tz=timezone.utc
            )
            ts_iso = ts_dt.strftime(_ISO)[:-3] + "Z"

            changeset = {
                "id": cs_id,
                "timestamp": ts_iso,
                "globalCounter": current_counter,
                "modelVersion": 1,
                "eventChanges": _convert_date_fields(_deserialize_zchangeset_blob(evc)),
                "timelineChanges": _convert_date_fields(_deserialize_zchangeset_blob(tlc)),
                "customColorChanges": _convert_date_fields(_deserialize_zchangeset_blob(cc)),
                "preferenceChanges": _convert_date_fields(_deserialize_zchangeset_blob(pc)),
                "goalChanges": _convert_date_fields(_deserialize_zchangeset_blob(gc)),
                "customObjectChanges": _convert_date_fields(_deserialize_zchangeset_blob(coc)),
            }
            try:
                resp = client.push_changeset(changeset, current_counter)
                if resp.get("serverRejectedIncomingChanges"):
                    errors.append(f"cs={cs_id[:8]} rejected by server")
                    continue
                current_counter = int(resp["newGlobalCounter"])
                conn.execute("DELETE FROM ZCHANGESET WHERE Z_PK = ?", (z_pk,))
                conn.commit()
                pushed += 1
            except Exception as e:
                errors.append(f"cs={cs_id[:8]} {e}")
                break  # stop on first failure to keep state consistent

        remaining = conn.execute(
            "SELECT COUNT(*) FROM ZCHANGESET WHERE ZSTATE = 2"
        ).fetchone()[0]
    finally:
        conn.close()

    return FlushResult(
        pushed=pushed,
        failed=len(errors),
        remaining=int(remaining),
        errors=errors,
    )

"""Cloud-state machinery for Timelines.app.

Generic CRUD surface on top of ``api.SyncClient`` plus a persistent cache of
the last-seen ``/sync`` state so we don't re-download every changeset on each
invocation. Knows about ``Event`` / ``Timeline`` / ``CustomObject`` records and
the cloud changeset wire format.

Countdown timers live as ``CustomObject`` records with
``objectType == "countdown-timer"`` (``stringValue1`` = timeline uid,
``stringValue2`` = name, ``stringValue3`` = duration seconds, ``stringValue4`` =
"true" while running). Starting one is two writes in a single changeset: a
running time-tracking ``Event`` plus a running countdown instance whose
``creationDate`` is the start time — the app then ticks it down and rings.
"""

from __future__ import annotations

import json
import os
import sys
import time
import uuid as _uuid
from dataclasses import dataclass
from datetime import datetime, timezone
from pathlib import Path
from typing import Any

from . import api
from .coredata import CHANGE_DELETE, CHANGE_PARTIAL, CHANGE_UPSERT, TimelinesStore
from .models import CustomObject, Event, Timeline

COUNTDOWN_OBJECT_TYPE = "countdown-timer"


EPOCH = datetime.fromtimestamp(0, tz=timezone.utc)


# ---------- time helpers (generic) ----------


def local_naive(dt: datetime) -> datetime:
    if dt.tzinfo is not None:
        return dt.astimezone().replace(tzinfo=None)
    return dt


def local_aware(dt: datetime) -> datetime:
    if dt.tzinfo is not None:
        return dt
    return dt.astimezone()


def local_tz_name() -> str:
    try:
        return time.tzname[0] or "UTC"
    except Exception:
        return "UTC"


def floor_min(dt: datetime) -> datetime:
    """Truncate to whole minutes. Useful when LWW-comparing timestamps that
    come from different clocks (e.g. file mtime vs. Core Data) so sub-minute
    jitter doesn't count as a real edit.
    """
    return dt.replace(second=0, microsecond=0)


# ---------- wire format helpers ----------


def fmt_iso_ms(dt: datetime) -> str:
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc).strftime("%Y-%m-%dT%H:%M:%S.%f")[:-3] + "Z"


def parse_iso(s: str | None) -> datetime | None:
    """Cloud returns ``2026-04-13T20:28:12.132Z``. Python <3.11 chokes on ``Z``."""
    if not s:
        return None
    if s.endswith("Z"):
        s = s[:-1] + "+00:00"
    try:
        return datetime.fromisoformat(s)
    except ValueError:
        return None


def now_iso() -> str:
    return fmt_iso_ms(datetime.now(timezone.utc))


def empty_changeset(counter: int) -> dict[str, Any]:
    return {
        "id": str(_uuid.uuid4()).upper(),
        "timestamp": fmt_iso_ms(datetime.now(timezone.utc)),
        "globalCounter": counter,
        "modelVersion": 1,
        "eventChanges": [],
        "timelineChanges": [],
        "customColorChanges": [],
        "preferenceChanges": [],
        "goalChanges": [],
        "customObjectChanges": [],
    }


def create_event_wire(
    uid: str,
    timeline_uid: str,
    *,
    name: str,
    notes: str,
    start: datetime,
    end: datetime,
    time_tracking_active: bool,
    marker_color: int,
) -> dict[str, Any]:
    """Build a full (changeType=100) upsert wire dict for an event.

    ``marker_color`` matters: the Timelines app uses the event's markerColor
    to render its bar, not the timeline's color directly. Almost all events
    in the wild have markerColor == timeline.color, so callers pass that.
    """
    start = local_aware(start)
    end = local_aware(end)
    now = now_iso()
    return {
        "changeType": CHANGE_UPSERT,
        "uniqueIdentifier": uid,
        "timelineIdentifier": timeline_uid,
        "name": name or "",
        "notes": notes or "",
        "startDate": fmt_iso_ms(start),
        "endDate": fmt_iso_ms(end),
        "lastModifiedDate": now,
        "dayIdentifier": start.astimezone().strftime("%Y-%m-%d"),
        "timeZone": local_tz_name(),
        "markerColor": int(marker_color),
        "markerSize": 1,
        "timeTrackingActive": time_tracking_active,
        "wasTimeTracked": True,
    }


def partial_event_wire(uid: str, **fields: Any) -> dict[str, Any]:
    """ChangeType=200 partial update. Always stamps lastModifiedDate."""
    wire: dict[str, Any] = {
        "changeType": CHANGE_PARTIAL,
        "uniqueIdentifier": uid,
        "lastModifiedDate": now_iso(),
    }
    wire.update(fields)
    return wire


def delete_event_wire(uid: str) -> dict[str, Any]:
    return {"changeType": CHANGE_DELETE, "uniqueIdentifier": uid}


def create_timeline_wire(uid: str, name: str, order: int) -> dict[str, Any]:
    now = now_iso()
    return {
        "changeType": CHANGE_UPSERT,
        "uniqueIdentifier": uid,
        "name": name,
        "notes": "",
        "color": 0,
        "order": order,
        "archived": False,
        "visible": True,
        "dailyGoal": 0,
        "weeklyGoal": 0,
        "monthlyGoal": 0,
        "goalsAreLimits": False,
        "creationTime": now,
        "lastModifiedDate": now,
    }


def custom_object_wire(
    uid: str,
    *,
    object_type: str,
    string_value_1: str = "",
    string_value_2: str = "",
    string_value_3: str = "",
    string_value_4: str = "",
    creation_date: datetime | None = None,
) -> dict[str, Any]:
    """Full (changeType=100) upsert wire dict for a CustomObject. Used for both
    create and edit — the app itself re-pushes whole records, so a full upsert is
    the reliable way to mutate one (e.g. flipping a countdown's running flag)."""
    now = now_iso()
    return {
        "changeType": CHANGE_UPSERT,
        "uniqueIdentifier": uid,
        "objectType": object_type,
        "stringValue1": string_value_1 or "",
        "stringValue2": string_value_2 or "",
        "stringValue3": string_value_3 or "",
        "stringValue4": string_value_4 or "",
        "creationDate": fmt_iso_ms(creation_date) if creation_date else now,
        "lastModifiedDate": now,
    }


def delete_custom_object_wire(uid: str) -> dict[str, Any]:
    return {"changeType": CHANGE_DELETE, "uniqueIdentifier": uid}


# ---------- object reconstruction from wire ----------


def event_from_upsert(ec: dict[str, Any]) -> Event:
    return Event(
        unique_identifier=ec["uniqueIdentifier"],
        timeline_identifier=ec.get("timelineIdentifier") or None,
        name=ec.get("name") or "",
        notes=ec.get("notes") or "",
        start_date=parse_iso(ec.get("startDate")),
        end_date=parse_iso(ec.get("endDate")),
        last_modified_date=parse_iso(ec.get("lastModifiedDate")),
        day_identifier=ec.get("dayIdentifier") or "",
        time_zone=ec.get("timeZone") or "",
        marker_color=int(ec.get("markerColor") or 0),
        marker_size=int(ec.get("markerSize") or 0),
        time_tracking_active=bool(ec.get("timeTrackingActive", False)),
        was_time_tracked=bool(ec.get("wasTimeTracked", False)),
    )


def apply_partial(e: Event, ec: dict[str, Any]) -> None:
    """changeType=200 carries only the fields that changed. Merge in place."""
    if "name" in ec:
        e.name = ec.get("name") or ""
    if "notes" in ec:
        e.notes = ec.get("notes") or ""
    if "startDate" in ec:
        e.start_date = parse_iso(ec.get("startDate"))
    if "endDate" in ec:
        e.end_date = parse_iso(ec.get("endDate"))
    if "lastModifiedDate" in ec:
        e.last_modified_date = parse_iso(ec.get("lastModifiedDate"))
    if "dayIdentifier" in ec:
        e.day_identifier = ec.get("dayIdentifier") or ""
    if "timeZone" in ec:
        e.time_zone = ec.get("timeZone") or ""
    if "markerColor" in ec:
        e.marker_color = int(ec.get("markerColor") or 0)
    if "markerSize" in ec:
        e.marker_size = int(ec.get("markerSize") or 0)
    if "timeTrackingActive" in ec:
        e.time_tracking_active = bool(ec.get("timeTrackingActive", False))
    if "wasTimeTracked" in ec:
        e.was_time_tracked = bool(ec.get("wasTimeTracked", False))
    if "timelineIdentifier" in ec:
        e.timeline_identifier = ec.get("timelineIdentifier") or None


def timeline_from_upsert(tc: dict[str, Any]) -> Timeline:
    return Timeline(
        unique_identifier=tc["uniqueIdentifier"],
        name=tc.get("name") or "",
        notes=tc.get("notes") or "",
        color=int(tc.get("color") or 0),
        order=int(tc.get("order") or 0),
        archived=bool(tc.get("archived", False)),
        visible=bool(tc.get("visible", True)),
        daily_goal=int(tc.get("dailyGoal") or 0),
        weekly_goal=int(tc.get("weeklyGoal") or 0),
        monthly_goal=int(tc.get("monthlyGoal") or 0),
        goals_are_limits=bool(tc.get("goalsAreLimits", False)),
        creation_time=parse_iso(tc.get("creationTime")),
        last_modified_date=parse_iso(tc.get("lastModifiedDate")),
    )


def apply_timeline_partial(t: Timeline, tc: dict[str, Any]) -> None:
    if "name" in tc:
        t.name = tc.get("name") or ""
    if "notes" in tc:
        t.notes = tc.get("notes") or ""
    if "color" in tc:
        t.color = int(tc.get("color") or 0)
    if "order" in tc:
        t.order = int(tc.get("order") or 0)
    if "archived" in tc:
        t.archived = bool(tc.get("archived", False))
    if "visible" in tc:
        t.visible = bool(tc.get("visible", True))
    if "lastModifiedDate" in tc:
        t.last_modified_date = parse_iso(tc.get("lastModifiedDate"))


def custom_object_from_upsert(co: dict[str, Any]) -> CustomObject:
    return CustomObject(
        unique_identifier=co["uniqueIdentifier"],
        object_type=co.get("objectType") or "",
        string_value_1=co.get("stringValue1") or "",
        string_value_2=co.get("stringValue2") or "",
        string_value_3=co.get("stringValue3") or "",
        string_value_4=co.get("stringValue4") or "",
        creation_date=parse_iso(co.get("creationDate")),
        last_modified_date=parse_iso(co.get("lastModifiedDate")),
    )


def apply_custom_object_partial(o: CustomObject, co: dict[str, Any]) -> None:
    if "objectType" in co:
        o.object_type = co.get("objectType") or ""
    for i in (1, 2, 3, 4):
        key = f"stringValue{i}"
        if key in co:
            setattr(o, f"string_value_{i}", co.get(key) or "")
    if "creationDate" in co:
        o.creation_date = parse_iso(co.get("creationDate"))
    if "lastModifiedDate" in co:
        o.last_modified_date = parse_iso(co.get("lastModifiedDate"))


def apply_changesets(
    changesets: list[dict[str, Any]],
    events: dict[str, Event],
    timelines: dict[str, Timeline],
    custom_objects: dict[str, CustomObject] | None = None,
) -> None:
    """Fold changesets into existing event + timeline state in-place.

    Changesets come in globalCounter order from the server; within one
    changeset we preserve list order, which matches the app's own writes.
    A partial change (200) against an unknown uuid is treated as an upsert
    on best-effort basis — in practice this happens when we receive a 200
    for an event that was created before our cache cursor.
    """
    changesets = sorted(changesets, key=lambda cs: cs.get("globalCounter") or 0)

    for cs in changesets:
        for ec in cs.get("eventChanges") or []:
            uid = ec.get("uniqueIdentifier")
            if not uid:
                continue
            ct = ec.get("changeType")
            if ct == CHANGE_UPSERT:
                events[uid] = event_from_upsert(ec)
            elif ct == CHANGE_PARTIAL:
                if uid in events:
                    apply_partial(events[uid], ec)
                else:
                    events[uid] = event_from_upsert(ec)
            elif ct == CHANGE_DELETE:
                events.pop(uid, None)

        for tc in cs.get("timelineChanges") or []:
            uid = tc.get("uniqueIdentifier")
            if not uid:
                continue
            ct = tc.get("changeType")
            if ct == CHANGE_UPSERT:
                timelines[uid] = timeline_from_upsert(tc)
            elif ct == CHANGE_PARTIAL:
                if uid in timelines:
                    apply_timeline_partial(timelines[uid], tc)
                else:
                    timelines[uid] = timeline_from_upsert(tc)
            elif ct == CHANGE_DELETE:
                timelines.pop(uid, None)

        if custom_objects is None:
            continue
        for co in cs.get("customObjectChanges") or []:
            uid = co.get("uniqueIdentifier")
            if not uid:
                continue
            ct = co.get("changeType")
            if ct == CHANGE_UPSERT:
                custom_objects[uid] = custom_object_from_upsert(co)
            elif ct == CHANGE_PARTIAL:
                if uid in custom_objects:
                    apply_custom_object_partial(custom_objects[uid], co)
                else:
                    custom_objects[uid] = custom_object_from_upsert(co)
            elif ct == CHANGE_DELETE:
                custom_objects.pop(uid, None)


def enrich_timeline_names(
    events: dict[str, Event], timelines: dict[str, Timeline]
) -> None:
    for e in events.values():
        if e.timeline_identifier and e.timeline_identifier in timelines:
            e.timeline_name = timelines[e.timeline_identifier].name


# ---------- cloud state cache ----------
#
# Persisting {counter, events, timelines} between runs lets us incremental-pull
# just the new changesets each invocation instead of re-downloading all ~30k
# events. Cache is a performance hint, not user data: delete it any time and
# the next pull does a full download.


CLOUD_CACHE_PATH = Path(
    os.environ.get("TIMETRACK_CLOUD_CACHE")
    or os.environ.get("XDG_CACHE_HOME", str(Path.home() / ".cache"))
) / "timetrack-cli" / "cloud-state.json"


def _event_to_cache_dict(e: Event) -> dict[str, Any]:
    def iso(dt: datetime | None) -> str | None:
        return dt.isoformat() if dt else None

    return {
        "uniqueIdentifier": e.unique_identifier,
        "timelineIdentifier": e.timeline_identifier or "",
        "name": e.name or "",
        "notes": e.notes or "",
        "startDate": iso(e.start_date),
        "endDate": iso(e.end_date),
        "lastModifiedDate": iso(e.last_modified_date),
        "dayIdentifier": e.day_identifier or "",
        "timeZone": e.time_zone or "",
        "markerColor": int(e.marker_color or 0),
        "markerSize": int(e.marker_size or 0),
        "timeTrackingActive": bool(e.time_tracking_active),
        "wasTimeTracked": bool(e.was_time_tracked),
    }


def _timeline_to_cache_dict(t: Timeline) -> dict[str, Any]:
    def iso(dt: datetime | None) -> str | None:
        return dt.isoformat() if dt else None

    return {
        "uniqueIdentifier": t.unique_identifier,
        "name": t.name or "",
        "notes": t.notes or "",
        "color": int(t.color or 0),
        "order": int(t.order or 0),
        "archived": bool(t.archived),
        "visible": bool(t.visible),
        "dailyGoal": int(t.daily_goal or 0),
        "weeklyGoal": int(t.weekly_goal or 0),
        "monthlyGoal": int(t.monthly_goal or 0),
        "goalsAreLimits": bool(t.goals_are_limits),
        "creationTime": iso(t.creation_time),
        "lastModifiedDate": iso(t.last_modified_date),
    }


def _custom_object_to_cache_dict(o: CustomObject) -> dict[str, Any]:
    def iso(dt: datetime | None) -> str | None:
        return dt.isoformat() if dt else None

    return {
        "uniqueIdentifier": o.unique_identifier,
        "objectType": o.object_type or "",
        "stringValue1": o.string_value_1 or "",
        "stringValue2": o.string_value_2 or "",
        "stringValue3": o.string_value_3 or "",
        "stringValue4": o.string_value_4 or "",
        "creationDate": iso(o.creation_date),
        "lastModifiedDate": iso(o.last_modified_date),
    }


def _load_cache(
    device_uuid: str,
) -> tuple[int, dict[str, Event], dict[str, Timeline], dict[str, CustomObject]]:
    """Return (counter, events, timelines, custom_objects). On any load failure
    — missing file, parse error, device-UUID mismatch — return (0, {}, {}, {})
    so the next pull is a full download.
    """
    try:
        raw = json.loads(CLOUD_CACHE_PATH.read_text(encoding="utf-8"))
    except (FileNotFoundError, json.JSONDecodeError, OSError):
        return 0, {}, {}, {}

    if raw.get("device_uuid") != device_uuid:
        # Different device identity — cache is meaningless, start fresh.
        return 0, {}, {}, {}

    if "customObjects" not in raw:
        # Old-format cache (pre custom-object support). Force one full re-pull so
        # custom objects created before the cursor get folded in.
        return 0, {}, {}, {}

    events: dict[str, Event] = {}
    for uid, d in (raw.get("events") or {}).items():
        try:
            events[uid] = event_from_upsert(d)
        except Exception:
            return 0, {}, {}, {}

    timelines: dict[str, Timeline] = {}
    for uid, d in (raw.get("timelines") or {}).items():
        try:
            timelines[uid] = timeline_from_upsert(d)
        except Exception:
            return 0, {}, {}, {}

    custom_objects: dict[str, CustomObject] = {}
    for uid, d in (raw.get("customObjects") or {}).items():
        try:
            custom_objects[uid] = custom_object_from_upsert(d)
        except Exception:
            return 0, {}, {}, {}

    return int(raw.get("counter") or 0), events, timelines, custom_objects


def save_cloud_state(
    counter: int,
    device_uuid: str,
    events: dict[str, Event],
    timelines: dict[str, Timeline],
    custom_objects: dict[str, CustomObject] | None = None,
) -> None:
    payload = {
        "counter": counter,
        "device_uuid": device_uuid,
        "events": {uid: _event_to_cache_dict(e) for uid, e in events.items()},
        "timelines": {uid: _timeline_to_cache_dict(t) for uid, t in timelines.items()},
        "customObjects": {
            uid: _custom_object_to_cache_dict(o)
            for uid, o in (custom_objects or {}).items()
        },
    }
    try:
        CLOUD_CACHE_PATH.parent.mkdir(parents=True, exist_ok=True)
        tmp = CLOUD_CACHE_PATH.with_suffix(".json.tmp")
        tmp.write_text(json.dumps(payload), encoding="utf-8")
        tmp.replace(CLOUD_CACHE_PATH)
    except OSError as ex:
        print(f"warn: failed to write cloud cache: {ex}", file=sys.stderr)


def fetch_cloud_state() -> tuple[
    dict[str, Event], dict[str, Timeline], dict[str, CustomObject], api.SyncClient, int
]:
    """Download cloud changesets since our last-seen counter and fold them
    into the cached state.

    Returns the mutable ``(events_by_uid, timelines_by_uid, custom_objects_by_uid)``
    dicts plus the authenticated client and the current globalCounter, so callers
    that want to POST follow-up changesets don't have to re-auth or re-fetch. The
    cache is persisted with the pulled-through counter; callers that push
    must call :func:`save_cloud_state` again with the post-push counter.
    """
    client = api.SyncClient()
    counter, events, timelines, custom_objects = _load_cache(client.auth.device_uuid)
    changesets = client.pull_changesets_since(counter)

    if changesets:
        apply_changesets(changesets, events, timelines, custom_objects)
        counter = max(
            (int(cs.get("globalCounter") or 0) for cs in changesets),
            default=counter,
        )
        save_cloud_state(counter, client.auth.device_uuid, events, timelines, custom_objects)
    elif counter == 0:
        # First-ever run with no changesets returned — empty cloud. Persist
        # so we don't retry from 0 on subsequent invocations.
        counter = client.discover_counter()
        save_cloud_state(counter, client.auth.device_uuid, events, timelines, custom_objects)

    enrich_timeline_names(events, timelines)
    return events, timelines, custom_objects, client, counter


# ---------- direct cloud writes (high-level helper) ----------


class PushEventsResult:
    def __init__(self) -> None:
        self.requested: int = 0
        self.created: int = 0
        self.skipped_existing: int = 0
        self.unknown_timelines: list[str] = []
        self.created_uids: list[str] = []
        self.dry_run: bool = False
        self.error: str | None = None


def push_events_to_cloud(
    entries: list[dict[str, Any]],
    *,
    dry_run: bool = False,
) -> PushEventsResult:
    """Push a batch of closed-interval events to the Timelines cloud.

    Each entry is a dict with keys:
      - ``timeline``: timeline NAME (resolved against current cloud state)
      - ``name``: event title (optional, defaults to "")
      - ``notes``: event notes (optional)
      - ``start``: ``datetime`` (timezone-aware preferred; naive treated as local)
      - ``end``: ``datetime``

    Dedup is by ``(timeline_uid, name, start_minute)`` against current cloud
    state — entries that already exist are skipped (idempotent).

    Returns a :class:`PushEventsResult` with counts and the list of new UIDs.
    """
    result = PushEventsResult()
    result.requested = len(entries)
    result.dry_run = dry_run
    if not entries:
        return result

    try:
        events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        result.error = f"cloud fetch failed: {ex}"
        return result

    by_name: dict[str, Timeline] = {t.name: t for t in timelines.values() if not t.archived}

    existing_keys: set[tuple[str, str, str]] = set()
    for e in events.values():
        if e.timeline_identifier and e.start_date:
            existing_keys.add((
                e.timeline_identifier,
                (e.name or "").strip(),
                fmt_iso_ms(local_aware(e.start_date))[:16],
            ))

    wires: list[dict[str, Any]] = []
    new_uids: list[str] = []
    unknown: set[str] = set()
    for entry in entries:
        tl_name = entry["timeline"]
        tl = by_name.get(tl_name)
        if not tl:
            unknown.add(tl_name)
            continue
        name = (entry.get("name") or "").strip()
        start = entry["start"]
        end = entry["end"]
        key = (tl.unique_identifier, name, fmt_iso_ms(local_aware(start))[:16])
        if key in existing_keys:
            result.skipped_existing += 1
            continue
        existing_keys.add(key)
        uid = str(_uuid.uuid4()).upper()
        wire = create_event_wire(
            uid,
            tl.unique_identifier,
            name=name,
            notes=entry.get("notes") or "",
            start=start,
            end=end,
            time_tracking_active=False,
            marker_color=tl.color,
        )
        wires.append(wire)
        new_uids.append(uid)

    result.unknown_timelines = sorted(unknown)
    if dry_run or not wires:
        result.created = 0 if dry_run else 0
        return result

    cs = empty_changeset(counter)
    cs["eventChanges"] = wires
    try:
        resp = client.push_changeset(cs, counter)
        if resp.get("serverRejectedIncomingChanges"):
            result.error = "server rejected create changeset"
            return result
    except Exception as ex:
        result.error = f"push failed: {ex}"
        return result

    result.created = len(wires)
    result.created_uids = new_uids
    return result


# ---------- timer operations (start / stop / edit / delete) ----------


class OpResult:
    """Outcome of a single write op. ``event`` is the affected event with the
    change applied (best-effort, for display). ``stopped`` is a timer that was
    stopped as a side effect of ``start``. ``wires`` are the changeset event
    wires (shown on --dry-run)."""

    def __init__(self) -> None:
        self.ok: bool = False
        self.dry_run: bool = False
        self.error: str | None = None
        self.event: Event | None = None
        self.stopped: Event | None = None
        self.wires: list[dict[str, Any]] = []


def find_running(events: dict[str, Event]) -> Event | None:
    """The time-tracking-active event, if any (latest-started wins on ties)."""
    running = [e for e in events.values() if e.time_tracking_active]
    if not running:
        return None
    running.sort(
        key=lambda e: local_aware(e.start_date)
        if e.start_date
        else EPOCH
    )
    return running[-1]


def resolve_timeline(timelines: dict[str, Timeline], ref: str) -> Timeline | None:
    """Resolve a timeline by exact name (case-insensitive), then unique UUID prefix."""
    ref = ref.strip()
    for t in timelines.values():
        if t.name.lower() == ref.lower():
            return t
    matches = [t for t in timelines.values() if t.unique_identifier.startswith(ref.upper())]
    return matches[0] if len(matches) == 1 else None


def resolve_event(events: dict[str, Event], ref: str) -> Event | None:
    """Resolve an event by full UUID or unique UUID prefix (e.g. the 8-char id)."""
    ref = ref.strip().upper()
    if ref in events:
        return events[ref]
    matches = [e for e in events.values() if e.unique_identifier.startswith(ref)]
    return matches[0] if len(matches) == 1 else None


def _commit(client: "api.SyncClient", counter: int, wires: list[dict[str, Any]]) -> str | None:
    """Push one event changeset. Returns an error string, or None on success."""
    cs = empty_changeset(counter)
    cs["eventChanges"] = wires
    try:
        resp = client.push_changeset(cs, counter)
    except Exception as ex:
        return f"push failed: {ex}"
    if resp.get("serverRejectedIncomingChanges"):
        return "server rejected changeset"
    return None


def start_timer(
    timeline_ref: str,
    *,
    name: str = "",
    notes: str = "",
    at: datetime | None = None,
    stop_running: bool = True,
    dry_run: bool = False,
) -> OpResult:
    """Start a running timer on a timeline. By default stops any currently
    running timer first (in the same changeset)."""
    r = OpResult()
    r.dry_run = dry_run
    try:
        events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    tl = resolve_timeline(timelines, timeline_ref)
    if tl is None:
        r.error = f"unknown timeline {timeline_ref!r}"
        return r
    start = local_aware(at or datetime.now(timezone.utc))
    wires: list[dict[str, Any]] = []
    if stop_running:
        running = find_running(events)
        if running is not None:
            wires.append(
                partial_event_wire(
                    running.unique_identifier,
                    endDate=fmt_iso_ms(start),
                    timeTrackingActive=False,
                )
            )
            running.end_date = start
            running.time_tracking_active = False
            r.stopped = running
    uid = str(_uuid.uuid4()).upper()
    wires.append(
        create_event_wire(
            uid,
            tl.unique_identifier,
            name=name or "",
            notes=notes or "",
            start=start,
            end=start,
            time_tracking_active=True,
            marker_color=tl.color,
        )
    )
    r.wires = wires
    r.event = Event(
        unique_identifier=uid,
        timeline_identifier=tl.unique_identifier,
        timeline_name=tl.name,
        name=name or "",
        notes=notes or "",
        start_date=start,
        end_date=start,
        marker_color=tl.color,
        time_tracking_active=True,
    )
    if dry_run:
        r.ok = True
        return r
    err = _commit(client, counter, wires)
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def add_event(
    timeline_ref: str,
    *,
    name: str = "",
    notes: str = "",
    start: datetime,
    end: datetime,
    dry_run: bool = False,
) -> OpResult:
    """Add a completed (closed-interval) event to a timeline.

    Unlike :func:`start_timer` this records a finished entry: it never touches
    the running timer and is not time-tracking-active. Use it to backfill past
    work the timer missed.
    """
    r = OpResult()
    r.dry_run = dry_run
    try:
        events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    tl = resolve_timeline(timelines, timeline_ref)
    if tl is None:
        r.error = f"unknown timeline {timeline_ref!r}"
        return r
    s = local_aware(start)
    e = local_aware(end)
    if e < s:
        r.error = "end is before start"
        return r
    uid = str(_uuid.uuid4()).upper()
    wire = create_event_wire(
        uid,
        tl.unique_identifier,
        name=name or "",
        notes=notes or "",
        start=s,
        end=e,
        time_tracking_active=False,
        marker_color=tl.color,
    )
    r.wires = [wire]
    r.event = Event(
        unique_identifier=uid,
        timeline_identifier=tl.unique_identifier,
        timeline_name=tl.name,
        name=name or "",
        notes=notes or "",
        start_date=s,
        end_date=e,
        marker_color=tl.color,
        time_tracking_active=False,
    )
    if dry_run:
        r.ok = True
        return r
    err = _commit(client, counter, [wire])
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def stop_timer(*, at: datetime | None = None, dry_run: bool = False) -> OpResult:
    """Stop the currently-running timer, setting its end to ``at`` (default now)."""
    r = OpResult()
    r.dry_run = dry_run
    try:
        events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    running = find_running(events)
    if running is None:
        r.error = "no timer running"
        return r
    end = local_aware(at or datetime.now(timezone.utc))
    if running.start_date and end < local_aware(running.start_date):
        r.error = "stop time is before the timer's start"
        return r
    wire = partial_event_wire(
        running.unique_identifier,
        endDate=fmt_iso_ms(end),
        timeTrackingActive=False,
    )
    running.end_date = end
    running.time_tracking_active = False
    r.wires = [wire]
    r.event = running
    if dry_run:
        r.ok = True
        return r
    err = _commit(client, counter, [wire])
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def edit_event(
    ref: str,
    *,
    name: str | None = None,
    timeline: str | None = None,
    notes: str | None = None,
    start: datetime | None = None,
    end: datetime | None = None,
    dry_run: bool = False,
) -> OpResult:
    """Partial-update an event. Only the provided fields change."""
    r = OpResult()
    r.dry_run = dry_run
    try:
        events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    ev = resolve_event(events, ref)
    if ev is None:
        r.error = f"no event matching id {ref!r}"
        return r
    fields: dict[str, Any] = {}
    if name is not None:
        fields["name"] = name
        ev.name = name
    if notes is not None:
        fields["notes"] = notes
        ev.notes = notes
    if start is not None:
        s = local_aware(start)
        fields["startDate"] = fmt_iso_ms(s)
        fields["dayIdentifier"] = s.astimezone().strftime("%Y-%m-%d")
        ev.start_date = s
    if end is not None:
        e = local_aware(end)
        fields["endDate"] = fmt_iso_ms(e)
        ev.end_date = e
    if timeline is not None:
        tl = resolve_timeline(timelines, timeline)
        if tl is None:
            r.error = f"unknown timeline {timeline!r}"
            return r
        fields["timelineIdentifier"] = tl.unique_identifier
        fields["markerColor"] = int(tl.color)
        ev.timeline_identifier = tl.unique_identifier
        ev.timeline_name = tl.name
        ev.marker_color = tl.color
    if not fields:
        r.error = "nothing to change (pass --name/--timeline/--start/--end/--notes)"
        return r
    if ev.start_date and ev.end_date and local_aware(ev.end_date) < local_aware(ev.start_date):
        r.error = "resulting end is before start"
        return r
    wire = partial_event_wire(ev.unique_identifier, **fields)
    r.wires = [wire]
    r.event = ev
    if dry_run:
        r.ok = True
        return r
    err = _commit(client, counter, [wire])
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def delete_event(ref: str, *, dry_run: bool = False) -> OpResult:
    """Delete an event by id (UUID or unique prefix)."""
    r = OpResult()
    r.dry_run = dry_run
    try:
        events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    ev = resolve_event(events, ref)
    if ev is None:
        r.error = f"no event matching id {ref!r}"
        return r
    r.event = ev
    r.wires = [delete_event_wire(ev.unique_identifier)]
    if dry_run:
        r.ok = True
        return r
    err = _commit(client, counter, r.wires)
    if err:
        r.error = err
        return r
    r.ok = True
    return r


# ---------- countdown timers ----------


@dataclass
class Countdown:
    """A countdown-timer preset, or a running instance (``running``). Built from
    a ``countdown-timer`` CustomObject joined to its timeline."""

    uid: str
    name: str
    timeline_uid: str
    timeline_name: str
    timeline_color: int
    duration_seconds: int
    running: bool
    started: datetime | None = None
    remaining_seconds: float | None = None


def _int_or_zero(s: str) -> int:
    try:
        return int(float(s))
    except (TypeError, ValueError):
        return 0


def _to_countdown(
    o: CustomObject, timelines: dict[str, Timeline], now: datetime
) -> Countdown:
    tl = timelines.get(o.string_value_1)
    running = (o.string_value_4 or "").lower() == "true"
    duration = _int_or_zero(o.string_value_3)
    remaining = None
    if running and o.creation_date:
        elapsed = (now - local_aware(o.creation_date)).total_seconds()
        remaining = duration - elapsed
    return Countdown(
        uid=o.unique_identifier,
        name=o.string_value_2 or "",
        timeline_uid=o.string_value_1 or "",
        timeline_name=tl.name if tl else "",
        timeline_color=tl.color if tl else 0,
        duration_seconds=duration,
        running=running,
        started=local_aware(o.creation_date) if running and o.creation_date else None,
        remaining_seconds=remaining,
    )


def list_countdowns() -> tuple[list[Countdown], str | None]:
    """All countdown timers (presets + any running), running first. Returns
    ``(countdowns, error)``."""
    try:
        _events, timelines, custom_objects, _client, _counter = fetch_cloud_state()
    except Exception as ex:
        return [], f"cloud fetch failed: {ex}"
    now = datetime.now(timezone.utc).astimezone()
    cds = [
        _to_countdown(o, timelines, now)
        for o in custom_objects.values()
        if o.object_type == COUNTDOWN_OBJECT_TYPE
    ]
    cds.sort(key=lambda c: (not c.running, c.timeline_name.lower(), c.name.lower()))
    return cds, None


class CountdownOp:
    """Outcome of a countdown start/stop. ``countdowns`` are the affected
    timers; ``stopped_event`` is a tracked event closed as a side effect."""

    def __init__(self) -> None:
        self.ok: bool = False
        self.dry_run: bool = False
        self.error: str | None = None
        self.countdowns: list[Countdown] = []
        self.stopped_event: Event | None = None
        self.event_wires: list[dict[str, Any]] = []
        self.custom_object_wires: list[dict[str, Any]] = []


def _commit_mixed(
    client: "api.SyncClient",
    counter: int,
    *,
    event_wires: list[dict[str, Any]] | None = None,
    custom_object_wires: list[dict[str, Any]] | None = None,
) -> str | None:
    """Push one changeset carrying event and/or custom-object changes."""
    cs = empty_changeset(counter)
    if event_wires:
        cs["eventChanges"] = event_wires
    if custom_object_wires:
        cs["customObjectChanges"] = custom_object_wires
    try:
        resp = client.push_changeset(cs, counter)
    except Exception as ex:
        return f"push failed: {ex}"
    if resp.get("serverRejectedIncomingChanges"):
        return "server rejected changeset"
    return None


def _running_countdowns(custom_objects: dict[str, CustomObject]) -> list[CustomObject]:
    return [
        o
        for o in custom_objects.values()
        if o.object_type == COUNTDOWN_OBJECT_TYPE
        and (o.string_value_4 or "").lower() == "true"
    ]


def start_countdown(
    timeline_ref: str,
    duration_seconds: int,
    *,
    name: str = "",
    at: datetime | None = None,
    stop_running: bool = True,
    dry_run: bool = False,
) -> CountdownOp:
    """Start a countdown timer: a running tracked event plus a running
    ``countdown-timer`` instance (creationDate = start). The app ticks it down
    and rings at zero on whichever device is syncing. By default stops any
    currently-running timer and countdown first (in the same changeset)."""
    r = CountdownOp()
    r.dry_run = dry_run
    if duration_seconds <= 0:
        r.error = "duration must be positive"
        return r
    try:
        events, timelines, custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    tl = resolve_timeline(timelines, timeline_ref)
    if tl is None:
        r.error = f"unknown timeline {timeline_ref!r}"
        return r
    start = local_aware(at or datetime.now(timezone.utc))
    event_wires: list[dict[str, Any]] = []
    object_wires: list[dict[str, Any]] = []

    if stop_running:
        running = find_running(events)
        if running is not None:
            event_wires.append(
                partial_event_wire(
                    running.unique_identifier,
                    endDate=fmt_iso_ms(start),
                    timeTrackingActive=False,
                )
            )
            running.end_date = start
            running.time_tracking_active = False
            r.stopped_event = running
        for o in _running_countdowns(custom_objects):
            object_wires.append(
                custom_object_wire(
                    o.unique_identifier,
                    object_type=COUNTDOWN_OBJECT_TYPE,
                    string_value_1=o.string_value_1,
                    string_value_2=o.string_value_2,
                    string_value_3=o.string_value_3,
                    string_value_4="false",
                    creation_date=o.creation_date,
                )
            )
            o.string_value_4 = "false"

    ev_uid = str(_uuid.uuid4()).upper()
    event_wires.append(
        create_event_wire(
            ev_uid,
            tl.unique_identifier,
            name=name or "",
            notes="",
            start=start,
            end=start,
            time_tracking_active=True,
            marker_color=tl.color,
        )
    )
    co_uid = str(_uuid.uuid4()).upper()
    object_wires.append(
        custom_object_wire(
            co_uid,
            object_type=COUNTDOWN_OBJECT_TYPE,
            string_value_1=tl.unique_identifier,
            string_value_2=name or "",
            string_value_3=str(int(duration_seconds)),
            string_value_4="true",
            creation_date=start,
        )
    )
    r.event_wires = event_wires
    r.custom_object_wires = object_wires
    r.countdowns = [
        Countdown(
            uid=co_uid,
            name=name or "",
            timeline_uid=tl.unique_identifier,
            timeline_name=tl.name,
            timeline_color=tl.color,
            duration_seconds=int(duration_seconds),
            running=True,
            started=start,
            remaining_seconds=float(int(duration_seconds)),
        )
    ]
    if dry_run:
        r.ok = True
        return r
    err = _commit_mixed(
        client, counter, event_wires=event_wires, custom_object_wires=object_wires
    )
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def stop_countdown(
    name: str | None = None, *, at: datetime | None = None, dry_run: bool = False
) -> CountdownOp:
    """Stop running countdown timer(s): flip the instance to idle and close the
    paired tracked event. With ``name`` only stops matching timers, else all."""
    r = CountdownOp()
    r.dry_run = dry_run
    try:
        events, timelines, custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    targets = _running_countdowns(custom_objects)
    if name:
        targets = [o for o in targets if (o.string_value_2 or "") == name]
    if not targets:
        r.error = f"no countdown running matching {name!r}" if name else "no countdown running"
        return r
    end = local_aware(at or datetime.now(timezone.utc))
    now = datetime.now(timezone.utc).astimezone()
    event_wires: list[dict[str, Any]] = []
    object_wires: list[dict[str, Any]] = []
    closed_uids: set[str] = set()

    for o in targets:
        object_wires.append(
            custom_object_wire(
                o.unique_identifier,
                object_type=COUNTDOWN_OBJECT_TYPE,
                string_value_1=o.string_value_1,
                string_value_2=o.string_value_2,
                string_value_3=o.string_value_3,
                string_value_4="false",
                creation_date=o.creation_date,
            )
        )
        r.countdowns.append(_to_countdown(o, timelines, now))
        # Close the paired running tracked event (same timeline + name), if any.
        for e in events.values():
            if (
                e.time_tracking_active
                and e.unique_identifier not in closed_uids
                and e.timeline_identifier == o.string_value_1
                and (e.name or "") == (o.string_value_2 or "")
            ):
                event_wires.append(
                    partial_event_wire(
                        e.unique_identifier,
                        endDate=fmt_iso_ms(end),
                        timeTrackingActive=False,
                    )
                )
                e.end_date = end
                e.time_tracking_active = False
                r.stopped_event = e
                closed_uids.add(e.unique_identifier)
                break

    r.event_wires = event_wires
    r.custom_object_wires = object_wires
    if dry_run:
        r.ok = True
        return r
    err = _commit_mixed(
        client, counter, event_wires=event_wires, custom_object_wires=object_wires
    )
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def add_countdown_preset(
    timeline_ref: str,
    name: str,
    duration_seconds: int,
    *,
    dry_run: bool = False,
) -> CountdownOp:
    """Create an idle countdown preset (a startable timer) on a timeline."""
    r = CountdownOp()
    r.dry_run = dry_run
    if duration_seconds <= 0:
        r.error = "duration must be positive"
        return r
    try:
        _events, timelines, _custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    tl = resolve_timeline(timelines, timeline_ref)
    if tl is None:
        r.error = f"unknown timeline {timeline_ref!r}"
        return r
    co_uid = str(_uuid.uuid4()).upper()
    wire = custom_object_wire(
        co_uid,
        object_type=COUNTDOWN_OBJECT_TYPE,
        string_value_1=tl.unique_identifier,
        string_value_2=name or "",
        string_value_3=str(int(duration_seconds)),
        string_value_4="false",
    )
    r.custom_object_wires = [wire]
    r.countdowns = [
        Countdown(
            uid=co_uid,
            name=name or "",
            timeline_uid=tl.unique_identifier,
            timeline_name=tl.name,
            timeline_color=tl.color,
            duration_seconds=int(duration_seconds),
            running=False,
        )
    ]
    if dry_run:
        r.ok = True
        return r
    err = _commit_mixed(client, counter, custom_object_wires=[wire])
    if err:
        r.error = err
        return r
    r.ok = True
    return r


def remove_countdown_preset(name: str, *, dry_run: bool = False) -> CountdownOp:
    """Delete countdown preset(s) by name (idle ones; running instances are left
    untouched — stop them first)."""
    r = CountdownOp()
    r.dry_run = dry_run
    try:
        _events, timelines, custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    now = datetime.now(timezone.utc).astimezone()
    targets = [
        o
        for o in custom_objects.values()
        if o.object_type == COUNTDOWN_OBJECT_TYPE
        and (o.string_value_2 or "") == name
        and (o.string_value_4 or "").lower() != "true"
    ]
    if not targets:
        r.error = f"no idle countdown preset named {name!r}"
        return r
    wires = [delete_custom_object_wire(o.unique_identifier) for o in targets]
    r.custom_object_wires = wires
    r.countdowns = [_to_countdown(o, timelines, now) for o in targets]
    if dry_run:
        r.ok = True
        return r
    err = _commit_mixed(client, counter, custom_object_wires=wires)
    if err:
        r.error = err
        return r
    r.ok = True
    return r

