3	import (
4		"fmt"
5		"math/big"
6		"strings"
7	
8		"github.com/google/uuid"
9	)
10	
11	// base58Alphabet is the Bitcoin Base58 alphabet Things.app uses for
12	// identifiers (no 0, O, I, l). Things decodes identifiers with
13	// BSIdentifierFromBase58String; anything it cannot decode to 16 bytes
14	// permanently corrupts the sync history and crashes the client.
15	const base58Alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
16	
17	// EncodeUUID encodes a UUID as canonical Base58: one leading '1' per
18	// leading zero byte, matching the identifiers Things.app itself emits.
19	func EncodeUUID(u uuid.UUID) string {
20		zeros := 0
21		for zeros < len(u) && u[zeros] == 0 {
22			zeros++
23		}
